import React, { useEffect, useRef } from 'react';

const CanvasBackground = () => {
  const backgroundRef = useRef(null);

  useEffect(() => {
    const el = backgroundRef.current;

    let t = 0;

    const animate = () => {
      const R = Math.floor(128 + 64*Math.cos( (10*t)/60 ));
      const G = Math.floor(128 + 64*Math.sin( (10*t)/60 ));
      const B = Math.floor(128 + 64*Math.sin( (10*t)/60 ));

      el.style.background = `radial-gradient(circle at 50% 50%, rgb(${R}, ${G}, ${B}), #000)`;

      t = t + 0.1;
      window.requestAnimationFrame(animate);
    };

    animate();
  }, []);

  return (
    <div ref={backgroundRef} style={{ position: 'fixed', top: 0, left: 0, zIndex: -1, width: '100vw', height: '100vh' }} />
  );
};


export default CanvasBackground;
